import React, { useState, useEffect } from 'react';

function Timer() {
  const [seconds, setSeconds] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setSeconds(prev => prev + 1);
    }, 1000);

    return () => clearInterval(interval); // Cleanup
  }, []); // Boş massiv – yalnız bir dəfə işləyir

  return <p>Saniyə: {seconds}</p>;
}

console.log('useEffect ilə saniyə sayğacı yaradıldı');

import React, { useState, useEffect } from 'react';

function UserProfile() {
  const [userId, setUserId] = useState(1);

  useEffect(() => {
    console.log(`User ${userId} üçün məlumat yüklənir`);
  }, [userId]); // userId dəyişəndə effekt yenidən işləyir

  return (
    <div>
      <p>İstifadəçi ID: {userId}</p>
      <button onClick={() => setUserId(userId + 1)}>Növbəti istifadəçi</button>
    </div>
  );
}

console.log('Asılılıq massivi ilə useEffect yaradıldı');

import React, { useState, useLayoutEffect } from 'react';

function LayoutExample() {
  const [width, setWidth] = useState(0);

  useLayoutEffect(() => {
    const element = document.getElementById('box');
    if (element) {
      setWidth(element.offsetWidth);
    }
  }, []);

  return (
    <div>
      <div id="box" style={{ width: '200px', height: '100px', background: 'lightblue' }}>
        Bu qutu
      </div>
      <p>Qutu eni: {width}px</p>
    </div>
  );
}

